import React, { useEffect, useRef, useState, useCallback } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import io from 'socket.io-client';
import Peer from 'simple-peer';
import VideoGrid from './VideoGrid';
import Controls from './Controls';
import ChatPanel from './Chat/ChatPanel';
import ParticipantsPanel from './Participants/ParticipantsPanel';
import HostControls from './HostControls/HostControls';
import './Room.css';

const socket = io({
  withCredentials: true,
  transports: ['websocket', 'polling'],
  reconnectionAttempts: 5,
  reconnectionDelay: 1000
});

function Room() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  
  // Video states
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [isAudioMuted, setIsAudioMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  
  // UI states
  const [showChat, setShowChat] = useState(false);
  const [showParticipants, setShowParticipants] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  
  // Meeting states
  const [meeting, setMeeting] = useState(null);
  const [participants, setParticipants] = useState([]);
  const [messages, setMessages] = useState([]);
  const [unreadMessages, setUnreadMessages] = useState(0);
  const [userRole, setUserRole] = useState('participant');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [socketConnected, setSocketConnected] = useState(false);
  const [raisedHands, setRaisedHands] = useState([]);
  const [layout, setLayout] = useState('grid'); // 'grid' or 'speaker'
  const [fullscreenParticipant, setFullscreenParticipant] = useState(null);
  
  const userVideo = useRef();
  const peersRef = useRef(new Map());
  const socketRef = useRef(socket);
  const pendingSignals = useRef(new Map());
  const chatEndRef = useRef(null);
  
  const user = JSON.parse(localStorage.getItem('user'));

  // Get host status from URL params
  const queryParams = new URLSearchParams(location.search);
  const isHostFromUrl = queryParams.get('host') === user?.id;

  // Scroll chat to bottom
  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  // Socket connection
  useEffect(() => {
    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected:', socketRef.current.id);
      setSocketConnected(true);
    });

    socketRef.current.on('connect_error', (err) => {
      console.error('❌ Socket connection error:', err);
      setSocketConnected(false);
    });

    socketRef.current.on('disconnect', () => {
      console.log('🔴 Socket disconnected');
      setSocketConnected(false);
    });

    return () => {
      socketRef.current.off('connect');
      socketRef.current.off('connect_error');
      socketRef.current.off('disconnect');
    };
  }, []);

  // Initialize meeting
  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }

    let isMounted = true;
    let stream = null;

    const initializeMedia = async () => {
      try {
        // Fetch meeting details
        const API = (await import('../services/api')).default;
        const { data } = await API.get(`/meetings/${roomId}`);
        console.log('📊 Meeting data:', data);
        
        if (!isMounted) return;
        setMeeting(data);
        
        // Determine user role
        const isHost = data.hostId._id === user.id || isHostFromUrl;
        setUserRole(isHost ? 'host' : 'participant');

        // Format participants
        const formattedParticipants = (data.participants || []).map(p => ({
          userId: p.userId?._id || p.userId,
          name: p.userId?.name || p.name || 'Unknown',
          email: p.userId?.email || p.email,
          role: p.role || 'participant',
          audio: true,
          video: true,
          isHost: p.userId?._id === data.hostId._id
        }));

        // Add host to participants list
        if (!formattedParticipants.find(p => p.userId === data.hostId._id)) {
          formattedParticipants.unshift({
            userId: data.hostId._id,
            name: data.hostName,
            email: data.hostEmail,
            role: 'host',
            audio: true,
            video: true,
            isHost: true
          });
        }

        setParticipants(formattedParticipants);

        // Get user media
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: {
            width: { ideal: 1280 },
            height: { ideal: 720 },
            facingMode: 'user'
          }, 
          audio: true 
        });
        
        if (!isMounted) return;
        
        console.log('✅ Got local stream');
        setLocalStream(stream);
        
        if (userVideo.current) {
          userVideo.current.srcObject = stream;
          try {
            await userVideo.current.play();
          } catch (playErr) {
            console.log('Play error:', playErr);
          }
        }
        
        setLoading(false);

        // Join room
        socketRef.current.emit('join-room', {
          roomId,
          userId: user.id,
          userName: user.name,
          role: isHost ? 'host' : 'participant'
        });

        console.log('📤 Joined room as:', isHost ? 'host' : 'participant');

        // Handle existing users
        socketRef.current.on('existing-users', (users) => {
          console.log('👥 Existing users:', users);
          
          users.forEach(remoteUser => {
            if (remoteUser.userId !== user.id && !peersRef.current.has(remoteUser.socketId)) {
              const peer = createPeer(remoteUser.socketId, stream);
              if (peer) {
                peersRef.current.set(remoteUser.socketId, {
                  peerId: remoteUser.socketId,
                  peer,
                  userName: remoteUser.userName,
                  userId: remoteUser.userId,
                  role: remoteUser.role || 'participant'
                });
              }
            }
          });
          
          setPeers(Array.from(peersRef.current.values()));
        });

        // Handle new user connecting
        socketRef.current.on('user-connected', (newUser) => {
          console.log('🟢 User connected:', newUser);
          
          if (newUser.userId !== user.id && !peersRef.current.has(newUser.socketId)) {
            const peer = addPeer(newUser.socketId, stream);
            if (peer) {
              peersRef.current.set(newUser.socketId, {
                peerId: newUser.socketId,
                peer,
                userName: newUser.userName,
                userId: newUser.userId,
                role: newUser.role || 'participant'
              });
              setPeers(Array.from(peersRef.current.values()));
              
              // Update participants list
              setParticipants(prev => {
                if (!prev.find(p => p.userId === newUser.userId)) {
                  return [...prev, {
                    userId: newUser.userId,
                    name: newUser.userName,
                    role: newUser.role || 'participant',
                    audio: true,
                    video: true
                  }];
                }
                return prev;
              });

              // Send chat history to new user
              socketRef.current.emit('request-chat-history', { roomId, targetSocketId: newUser.socketId });
            }
          }
        });

        // Handle chat messages
        socketRef.current.on('chat-message', ({ userId, userName, message, timestamp }) => {
          console.log('💬 Chat message:', userName, message);
          setMessages(prev => [...prev, { userId, userName, message, timestamp }]);
          if (!showChat) {
            setUnreadMessages(prev => prev + 1);
          }
        });

        socketRef.current.on('chat-history', (history) => {
          console.log('📜 Chat history:', history);
          setMessages(history);
        });

        // Handle reactions
        socketRef.current.on('reaction', ({ userId, userName, reaction }) => {
          console.log('🎉 Reaction:', userName, reaction);
          // Show reaction temporarily
          const reactionElement = document.createElement('div');
          reactionElement.className = 'reaction-emoji';
          reactionElement.textContent = reaction;
          reactionElement.style.position = 'absolute';
          reactionElement.style.left = Math.random() * 80 + 10 + '%';
          reactionElement.style.top = Math.random() * 80 + 10 + '%';
          reactionElement.style.fontSize = '32px';
          reactionElement.style.animation = 'floatUp 2s ease-out';
          
          const videoGrid = document.querySelector('.video-grid');
          if (videoGrid) {
            videoGrid.appendChild(reactionElement);
            setTimeout(() => reactionElement.remove(), 2000);
          }
        });

        // Handle hand raise
        socketRef.current.on('hand-raised', ({ userId, userName }) => {
          console.log('✋ Hand raised:', userName);
          setRaisedHands(prev => [...prev, { userId, userName }]);
        });

        socketRef.current.on('hand-lowered', ({ userId }) => {
          console.log('👇 Hand lowered:', userId);
          setRaisedHands(prev => prev.filter(h => h.userId !== userId));
        });

        // Handle offer
        socketRef.current.on('offer', ({ offer, fromSocketId }) => {
          console.log('📞 Received offer from:', fromSocketId);
          
          if (!peersRef.current.has(fromSocketId)) {
            const peer = addPeer(fromSocketId, stream);
            if (peer) {
              peersRef.current.set(fromSocketId, {
                peerId: fromSocketId,
                peer,
                userName: 'Participant',
                userId: 'unknown'
              });
              
              setTimeout(() => {
                const peerData = peersRef.current.get(fromSocketId);
                if (peerData && peerData.peer && !peerData.peer.destroyed) {
                  peerData.peer.signal(offer);
                }
              }, 500);
              
              setPeers(Array.from(peersRef.current.values()));
            }
          }
        });

        // Handle answer
        socketRef.current.on('answer', ({ answer, fromSocketId }) => {
          const peerData = peersRef.current.get(fromSocketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            setTimeout(() => {
              if (peerData.peer && !peerData.peer.destroyed) {
                peerData.peer.signal(answer);
              }
            }, 100);
          }
        });

        // Handle ICE candidate
        socketRef.current.on('ice-candidate', ({ candidate, fromSocketId }) => {
          const peerData = peersRef.current.get(fromSocketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            peerData.peer.signal(candidate);
          }
        });

        // Handle user disconnect
        socketRef.current.on('user-disconnected', (socketId) => {
          console.log('🔴 User disconnected:', socketId);
          
          const peerData = peersRef.current.get(socketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            peerData.peer.destroy();
          }
          
          peersRef.current.delete(socketId);
          setPeers(Array.from(peersRef.current.values()));
          
          // Remove from participants list
          setParticipants(prev => prev.filter(p => p.socketId !== socketId));
          
          // Remove from raised hands
          const disconnectedUser = participants.find(p => p.socketId === socketId);
          if (disconnectedUser) {
            setRaisedHands(prev => prev.filter(h => h.userId !== disconnectedUser.userId));
          }
        });

        // Handle role updates
        socketRef.current.on('participant-role-updated', ({ userId, newRole }) => {
          if (userId === user.id) {
            setUserRole(newRole);
          }
          
          setParticipants(prev => prev.map(p => 
            p.userId === userId ? { ...p, role: newRole } : p
          ));
        });

        // Handle mute events
        socketRef.current.on('participant-muted', ({ userId }) => {
          if (userId === user.id) {
            setIsAudioMuted(true);
            if (stream) {
              stream.getAudioTracks()[0].enabled = false;
            }
          }
          
          setParticipants(prev => prev.map(p => 
            p.userId === userId ? { ...p, audio: false } : p
          ));
        });

        socketRef.current.on('participant-unmuted', ({ userId }) => {
          if (userId === user.id) {
            setIsAudioMuted(false);
            if (stream) {
              stream.getAudioTracks()[0].enabled = true;
            }
          }
          
          setParticipants(prev => prev.map(p => 
            p.userId === userId ? { ...p, audio: true } : p
          ));
        });

        // Handle video toggle
        socketRef.current.on('participant-video-off', ({ userId }) => {
          if (userId === user.id) {
            setIsVideoOff(true);
            if (stream) {
              stream.getVideoTracks()[0].enabled = false;
            }
          }
          
          setParticipants(prev => prev.map(p => 
            p.userId === userId ? { ...p, video: false } : p
          ));
        });

        socketRef.current.on('participant-video-on', ({ userId }) => {
          if (userId === user.id) {
            setIsVideoOff(false);
            if (stream) {
              stream.getVideoTracks()[0].enabled = true;
            }
          }
          
          setParticipants(prev => prev.map(p => 
            p.userId === userId ? { ...p, video: true } : p
          ));
        });

        // Handle participant removed
        socketRef.current.on('participant-removed', ({ userId }) => {
          if (userId === user.id) {
            alert('You have been removed from the meeting');
            navigate('/');
          }
        });

        // Handle meeting ended
        socketRef.current.on('meeting-ended', () => {
          alert('The meeting has ended');
          navigate('/');
        });

        // Handle recording status
        socketRef.current.on('recording-started', () => {
          alert('Recording has started');
        });

        socketRef.current.on('recording-stopped', () => {
          alert('Recording has stopped');
        });

      } catch (err) {
        console.error('❌ Error:', err);
        if (isMounted) {
          setError(err.message);
          setLoading(false);
        }
      }
    };

    initializeMedia();

    return () => {
      isMounted = false;
      cleanup();
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [roomId, user?.id, isHostFromUrl, navigate]);

  const createPeer = (targetSocketId, stream) => {
    try {
      const peer = new Peer({
        initiator: true,
        trickle: false,
        stream,
        config: {
          iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:stun1.l.google.com:19302' },
            { urls: 'stun:stun2.l.google.com:19302' },
            { urls: 'stun:stun3.l.google.com:19302' },
            { urls: 'stun:stun4.l.google.com:19302' }
          ]
        }
      });

      peer.on('signal', signal => {
        if (socketRef.current.connected) {
          socketRef.current.emit('offer', {
            targetSocketId,
            offer: signal
          });
        }
      });

      peer.on('stream', (remoteStream) => {
        console.log('✅ Received remote stream from:', targetSocketId);
      });

      peer.on('connect', () => {
        console.log('✅ Peer connected to:', targetSocketId);
      });

      peer.on('error', (err) => {
        console.error('❌ Peer error:', err);
      });

      return peer;
    } catch (err) {
      console.error('Error creating peer:', err);
      return null;
    }
  };

  const addPeer = (targetSocketId, stream) => {
    try {
      const peer = new Peer({
        initiator: false,
        trickle: false,
        stream,
        config: {
          iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:stun1.l.google.com:19302' },
            { urls: 'stun:stun2.l.google.com:19302' },
            { urls: 'stun:stun3.l.google.com:19302' },
            { urls: 'stun:stun4.l.google.com:19302' }
          ]
        }
      });

      peer.on('signal', signal => {
        if (socketRef.current.connected) {
          socketRef.current.emit('answer', {
            targetSocketId,
            answer: signal
          });
        }
      });

      peer.on('stream', (remoteStream) => {
        console.log('✅ Received remote stream from:', targetSocketId);
      });

      peer.on('connect', () => {
        console.log('✅ Peer connected to:', targetSocketId);
      });

      peer.on('error', (err) => {
        console.error('❌ Peer error:', err);
      });

      return peer;
    } catch (err) {
      console.error('Error adding peer:', err);
      return null;
    }
  };

  const cleanup = () => {
    socketRef.current.off('existing-users');
    socketRef.current.off('user-connected');
    socketRef.current.off('offer');
    socketRef.current.off('answer');
    socketRef.current.off('ice-candidate');
    socketRef.current.off('user-disconnected');
    socketRef.current.off('participant-role-updated');
    socketRef.current.off('participant-muted');
    socketRef.current.off('participant-unmuted');
    socketRef.current.off('participant-video-off');
    socketRef.current.off('participant-video-on');
    socketRef.current.off('participant-removed');
    socketRef.current.off('meeting-ended');
    socketRef.current.off('chat-message');
    socketRef.current.off('chat-history');
    socketRef.current.off('reaction');
    socketRef.current.off('hand-raised');
    socketRef.current.off('hand-lowered');
    socketRef.current.off('recording-started');
    socketRef.current.off('recording-stopped');
    
    peersRef.current.forEach(({ peer }) => {
      if (peer && !peer.destroyed) {
        peer.destroy();
      }
    });
    peersRef.current.clear();
    pendingSignals.current.clear();
  };

  const toggleAudio = () => {
    if (localStream) {
      const audioTrack = localStream.getAudioTracks()[0];
      if (audioTrack) {
        const newMutedState = !audioTrack.enabled;
        audioTrack.enabled = !newMutedState;
        setIsAudioMuted(newMutedState);
        socketRef.current.emit('toggle-audio', { roomId, isMuted: newMutedState });
        
        // Update participants list
        setParticipants(prev => prev.map(p => 
          p.userId === user.id ? { ...p, audio: !newMutedState } : p
        ));
      }
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      const videoTrack = localStream.getVideoTracks()[0];
      if (videoTrack) {
        const newVideoState = !videoTrack.enabled;
        videoTrack.enabled = !newVideoState;
        setIsVideoOff(newVideoState);
        socketRef.current.emit('toggle-video', { roomId, isVideoOff: newVideoState });
        
        // Update participants list
        setParticipants(prev => prev.map(p => 
          p.userId === user.id ? { ...p, video: !newVideoState } : p
        ));
      }
    }
  };

  const sendMessage = (message) => {
    if (message.trim()) {
      const newMessage = {
        userId: user.id,
        userName: user.name,
        message: message.trim(),
        timestamp: new Date().toISOString()
      };
      setMessages(prev => [...prev, newMessage]);
      socketRef.current.emit('send-message', {
        roomId,
        ...newMessage
      });
    }
  };

  const sendReaction = (reaction) => {
    socketRef.current.emit('send-reaction', {
      roomId,
      userId: user.id,
      userName: user.name,
      reaction
    });
  };

  const raiseHand = () => {
    if (raisedHands.some(h => h.userId === user.id)) {
      socketRef.current.emit('lower-hand', { roomId, userId: user.id });
      setRaisedHands(prev => prev.filter(h => h.userId !== user.id));
    } else {
      socketRef.current.emit('raise-hand', { roomId, userId: user.id, userName: user.name });
    }
  };

  const leaveRoom = () => {
    cleanup();
    navigate('/');
  };

  // Host control functions
  const handleMuteAll = () => {
    socketRef.current.emit('mute-all', { roomId });
  };

  const handleMuteParticipant = (participantId) => {
    socketRef.current.emit('mute-participant', { roomId, participantId });
  };

  const handleRemoveParticipant = (participantId) => {
    if (window.confirm('Remove this participant?')) {
      socketRef.current.emit('remove-participant', { roomId, participantId });
      
      // Remove from participants list
      setParticipants(prev => prev.filter(p => p.userId !== participantId));
      
      // Remove from peers
      const peerToRemove = Array.from(peersRef.current.entries()).find(([_, data]) => data.userId === participantId);
      if (peerToRemove) {
        const [socketId, peerData] = peerToRemove;
        if (peerData.peer && !peerData.peer.destroyed) {
          peerData.peer.destroy();
        }
        peersRef.current.delete(socketId);
        setPeers(Array.from(peersRef.current.values()));
      }
    }
  };

  const handleMakeCoHost = (participantId) => {
    socketRef.current.emit('make-cohost', { roomId, participantId });
    
    // Update local state
    setParticipants(prev => prev.map(p => 
      p.userId === participantId ? { ...p, role: 'co-host' } : p
    ));
    
    // Update peers
    peersRef.current.forEach((data, socketId) => {
      if (data.userId === participantId) {
        peersRef.current.set(socketId, { ...data, role: 'co-host' });
      }
    });
  };

  const handleRemoveCohost = (participantId) => {
    socketRef.current.emit('remove-cohost', { roomId, participantId });
    
    // Update local state
    setParticipants(prev => prev.map(p => 
      p.userId === participantId ? { ...p, role: 'participant' } : p
    ));
    
    // Update peers
    peersRef.current.forEach((data, socketId) => {
      if (data.userId === participantId) {
        peersRef.current.set(socketId, { ...data, role: 'participant' });
      }
    });
  };

  const handleEndMeeting = () => {
    if (window.confirm('End meeting for everyone?')) {
      socketRef.current.emit('end-meeting', { roomId });
      navigate('/');
    }
  };

  const handleUpdateSettings = (settings) => {
    socketRef.current.emit('update-meeting-settings', { roomId, ...settings });
    setMeeting(prev => ({ ...prev, settings: { ...prev.settings, ...settings } }));
  };

  const handleLowerAllHands = () => {
    socketRef.current.emit('lower-all-hands', { roomId });
    setRaisedHands([]);
  };

  const handleStartRecording = () => {
    socketRef.current.emit('start-recording', { roomId });
  };

  const handleStopRecording = () => {
    socketRef.current.emit('stop-recording', { roomId });
  };

  const handleLayoutChange = (newLayout) => {
    setLayout(newLayout);
  };

  const handleFullscreen = (participantId) => {
    setFullscreenParticipant(fullscreenParticipant === participantId ? null : participantId);
  };

  if (!socketConnected && !error) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Connecting to server...</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading meeting...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <div className="error-card">
          <i className="fas fa-exclamation-circle"></i>
          <h2>Error</h2>
          <p>{error}</p>
          <button onClick={() => navigate('/')} className="home-btn">
            Go to Home
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="room-container">
      {/* Top bar with meeting info */}
      <div className="meeting-top-bar">
        <div className="meeting-info">
          <h2>{meeting?.title}</h2>
          <span className="meeting-id">ID: {roomId}</span>
          {meeting?.settings?.waitingRoom && (
            <span className="badge waiting-room">Waiting Room Enabled</span>
          )}
          {meeting?.settings?.recordMeeting && (
            <span className="badge recording">
              <i className="fas fa-circle"></i> Recording
            </span>
          )}
        </div>
        <div className="meeting-controls-top">
          <button 
            className={`top-btn ${showParticipants ? 'active' : ''}`}
            onClick={() => {
              setShowParticipants(!showParticipants);
              setShowChat(false);
            }}
            title="Participants"
          >
            <i className="fas fa-users"></i>
            <span className="badge-count">{participants.length + 1}</span>
          </button>
          <button 
            className={`top-btn ${showChat ? 'active' : ''}`}
            onClick={() => {
              setShowChat(!showChat);
              setShowParticipants(false);
              setUnreadMessages(0);
            }}
            title="Chat"
          >
            <i className="fas fa-comment"></i>
            {unreadMessages > 0 && <span className="unread-badge">{unreadMessages}</span>}
          </button>
          <button 
            className="top-btn"
            onClick={() => setShowSettings(!showSettings)}
            title="Settings"
          >
            <i className="fas fa-cog"></i>
          </button>
        </div>
      </div>

      {/* Main content area */}
      <div className="room-content">
        {/* Video grid */}
        <div className={`video-section ${(showChat || showParticipants) ? 'with-sidebar' : ''}`}>
          <VideoGrid
            localStream={localStream}
            localUserName={user?.name}
            localRole={userRole}
            localUserId={user?.id}
            peers={peers}
            userVideoRef={userVideo}
            isAudioMuted={isAudioMuted}
            isVideoOff={isVideoOff}
            layout={layout}
            fullscreenParticipant={fullscreenParticipant}
            onFullscreen={handleFullscreen}
            raisedHands={raisedHands}
          />
        </div>

        {/* Sidebar for chat/participants */}
        {(showChat || showParticipants) && (
          <div className="sidebar">
            <div className="sidebar-tabs">
              <button 
                className={`tab ${showParticipants ? 'active' : ''}`}
                onClick={() => {
                  setShowParticipants(true);
                  setShowChat(false);
                }}
              >
                <i className="fas fa-users"></i>
                Participants ({participants.length + 1})
                {raisedHands.length > 0 && userRole === 'host' && (
                  <span className="hand-badge">{raisedHands.length}</span>
                )}
              </button>
              <button 
                className={`tab ${showChat ? 'active' : ''}`}
                onClick={() => {
                  setShowChat(true);
                  setShowParticipants(false);
                  setUnreadMessages(0);
                }}
              >
                <i className="fas fa-comment"></i>
                Chat
              </button>
            </div>

            <div className="sidebar-content">
              {showParticipants ? (
                <ParticipantsPanel
                  participants={participants}
                  currentUser={{ id: user.id, name: user.name, role: userRole }}
                  localUser={{ id: user.id, name: user.name, role: userRole }}
                  raisedHands={raisedHands}
                  onMuteAll={handleMuteAll}
                  onMuteParticipant={handleMuteParticipant}
                  onRemoveParticipant={handleRemoveParticipant}
                  onMakeCoHost={handleMakeCoHost}
                  onRemoveCohost={handleRemoveCohost}
                  onLowerAllHands={handleLowerAllHands}
                  userRole={userRole}
                />
              ) : (
                <ChatPanel
                  messages={messages}
                  currentUser={user}
                  onSendMessage={sendMessage}
                  onSendReaction={sendReaction}
                  chatEndRef={chatEndRef}
                />
              )}
            </div>
          </div>
        )}
      </div>

      {/* Bottom controls */}
      <Controls
        isAudioMuted={isAudioMuted}
        isVideoOff={isVideoOff}
        toggleAudio={toggleAudio}
        toggleVideo={toggleVideo}
        leaveRoom={leaveRoom}
        role={userRole}
        onRaiseHand={raiseHand}
        isHandRaised={raisedHands.some(h => h.userId === user.id)}
        onLayoutChange={handleLayoutChange}
        currentLayout={layout}
      />

      {/* Host controls panel */}
      {showSettings && userRole === 'host' && (
        <HostControls
          meeting={meeting}
          socket={socketRef.current}
          participants={participants}
          currentUser={{ id: user.id, role: userRole }}
          onMuteAll={handleMuteAll}
          onRemoveParticipant={handleRemoveParticipant}
          onMakeCoHost={handleMakeCoHost}
          onRemoveCohost={handleRemoveCohost}
          onEndMeeting={handleEndMeeting}
          onUpdateSettings={handleUpdateSettings}
          onLowerAllHands={handleLowerAllHands}
          onStartRecording={handleStartRecording}
          onStopRecording={handleStopRecording}
          onClose={() => setShowSettings(false)}
        />
      )}
    </div>
  );
}

export default Room;