import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import API from '../../services/api';
import ParticipantForm from './ParticipantForm';
import WaitingRoom from './WaitingRoom';
import './JoinMeeting.css';

function JoinMeeting() {
  const { roomId: urlRoomId } = useParams();
  const [joinData, setJoinData] = useState({
    roomId: urlRoomId || '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [meetingInfo, setMeetingInfo] = useState(null);
  const [showParticipantForm, setShowParticipantForm] = useState(false);
  const [showWaitingRoom, setShowWaitingRoom] = useState(false);
  const [needsPassword, setNeedsPassword] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (urlRoomId) {
      setJoinData(prev => ({ ...prev, roomId: urlRoomId }));
    }
  }, [urlRoomId]);

  const handleChange = (e) => {
    setJoinData({
      ...joinData,
      [e.target.name]: e.target.value
    });
    setError('');
    setNeedsPassword(false);
  };

  const validateMeeting = async () => {
    setLoading(true);
    setError('');
    setNeedsPassword(false);

    try {
      console.log('🔍 Validating meeting with data:', joinData);
      
      const response = await fetch('https://zoom-clone-3-uibx.onrender.com/api/meetings/validate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(joinData)
      });
      
      const data = await response.json();
      console.log('✅ Validation response:', data);
      
      if (data.valid) {
        setMeetingInfo(data.meeting);
        setShowParticipantForm(true);
      } else {
        setError(data.message || 'Invalid meeting');
      }
    } catch (err) {
      console.error('❌ Validation error:', err);
      setError('Failed to connect to server');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    validateMeeting();
  };

  const handleParticipantSubmit = async (participantData) => {
    setLoading(true);
    try {
      console.log('📝 Submitting participant data:', participantData);
console.log(API`/meetings/${joinData.roomId}/register`)
      const { data } = await API.post(`/meetings/${joinData.roomId}/register`, {
        name: participantData.name,
        email: participantData.email,
        mobile: participantData.mobile || ''
      });

      console.log('✅ Registration response:', data);

      if (data.requiresWaitingRoom) {
        setShowWaitingRoom(true);
        setShowParticipantForm(false);
      } else {
        navigate(`/guest-room/${joinData.roomId}?name=${encodeURIComponent(participantData.name)}`);
      }
    } catch (err) {
      console.error('❌ Registration error:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Failed to join meeting');
    } finally {
      setLoading(false);
    }
  };

  const handleWaitingRoomCancel = () => {
    setShowWaitingRoom(false);
    setShowParticipantForm(true);
  };

  // Show waiting room
  if (showWaitingRoom) {
    return (
      <WaitingRoom
        roomId={joinData.roomId}
        meetingInfo={meetingInfo}
        onCancel={handleWaitingRoomCancel}
      />
    );
  }

  // Show participant form
  if (showParticipantForm && meetingInfo) {
    console.log('✅ Rendering ParticipantForm');
    return (
      <ParticipantForm
        roomId={joinData.roomId}
        meetingDetails={meetingInfo}
        onSubmit={handleParticipantSubmit}
        onCancel={() => {
          setShowParticipantForm(false);
          setMeetingInfo(null);
        }}
      />
    );
  }

  // Main join form
  return (
    <div className="join-meeting-container">
      <div className="join-meeting-card">
        <div className="join-header">
          <h2>Join Meeting</h2>
          <p>Enter meeting details to continue</p>
        </div>

        {error && (
          <div className={`error-message ${needsPassword ? 'password-error' : ''}`}>
            <i className="fas fa-exclamation-circle"></i>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Meeting ID</label>
            <input
              type="text"
              name="roomId"
              value={joinData.roomId}
              onChange={handleChange}
              placeholder="Enter meeting ID"
              required
              disabled={!!urlRoomId || loading}
            />
          </div>

          <div className="form-group">
            <label>
              Password
              {meetingInfo?.password && <span className="required-badge">Required</span>}
            </label>
            <input
              type="password"
              name="password"
              value={joinData.password}
              onChange={handleChange}
              placeholder={needsPassword ? "This meeting requires a password" : "Enter meeting password (if required)"}
              disabled={loading}
              className={needsPassword ? 'required-field' : ''}
            />
            {needsPassword && (
              <small className="password-hint">
                This meeting is password protected. Please enter the password to continue.
              </small>
            )}
          </div>

          <button
            type="submit"
            disabled={loading}
            className="join-btn"
          >
            {loading ? (
              <>
                <i className="fas fa-spinner fa-spin"></i>
                Validating...
              </>
            ) : (
              <>
                <i className="fas fa-sign-in-alt"></i>
                Continue
              </>
            )}
          </button>
        </form>

        <div className="join-footer">
          <p>Want to create a meeting?</p>
          <button
            type="button"
            className="create-link-btn"
            onClick={() => navigate('/create')}
          >
            Create a Meeting
          </button>
        </div>

        {urlRoomId && (
          <div className="meeting-info">
            <p>
              <i className="fas fa-info-circle"></i>
              Meeting ID: <strong>{urlRoomId}</strong>
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

export default JoinMeeting;