import React, { useState } from 'react';
import './MeetingLink.css';

function MeetingLinks({ meetingLinks, roomId, onClose }) {
  const [copiedField, setCopiedField] = useState('');

  const copyToClipboard = (text, field) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(''), 2000);
  };

  return (
    <div className="meeting-links-modal">
      <div className="modal-content">
        <div className="modal-header">
          <h2>🎉 Meeting Created Successfully!</h2>
          <button className="close-btn" onClick={onClose}>×</button>
        </div>

        <div className="modal-body">
          <div className="room-id-section">
            <h3>Meeting ID</h3>
            <div className="room-id-display">
              <span className="room-id">{roomId}</span>
              <button 
                className="copy-btn"
                onClick={() => copyToClipboard(roomId, 'roomId')}
              >
                <i className={`fas ${copiedField === 'roomId' ? 'fa-check' : 'fa-copy'}`}></i>
                {copiedField === 'roomId' ? 'Copied!' : 'Copy'}
              </button>
            </div>
            <p className="info-text">Share this ID with participants to join</p>
          </div>

          <div className="links-section">
            <h3>Meeting Links</h3>
            
            {/* Host Link */}
            <div className="link-card host-card">
              <div className="link-header">
                <span className="link-badge host">👑 Host Link</span>
                <span className="link-privilege">Full Control</span>
              </div>
              <div className="link-content">
                <div className="link-url">{meetingLinks.hostLink}</div>
                <button 
                  className="copy-link-btn"
                  onClick={() => copyToClipboard(meetingLinks.hostLink, 'host')}
                >
                  <i className={`fas ${copiedField === 'host' ? 'fa-check' : 'fa-copy'}`}></i>
                  {copiedField === 'host' ? 'Copied!' : 'Copy Link'}
                </button>
              </div>
              <p className="link-description">
                Use this link to join as host with full control
              </p>
            </div>

            {/* Participant Link */}
            <div className="link-card participant-card">
              <div className="link-header">
                <span className="link-badge participant">👤 Participant Link</span>
                <span className="link-privilege">Basic Access</span>
              </div>
              <div className="link-content">
                <div className="link-url">{meetingLinks.participantLink}</div>
                <button 
                  className="copy-link-btn"
                  onClick={() => copyToClipboard(meetingLinks.participantLink, 'participant')}
                >
                  <i className={`fas ${copiedField === 'participant' ? 'fa-check' : 'fa-copy'}`}></i>
                  {copiedField === 'participant' ? 'Copied!' : 'Copy Link'}
                </button>
              </div>
              <p className="link-description">
                Share this link with participants to join
              </p>
            </div>
          </div>
        </div>

        <div className="modal-footer">
          <button className="join-now-btn" onClick={() => window.location.href = meetingLinks.hostLink}>
            <i className="fas fa-video"></i> Join as Host Now
          </button>
          <button className="close-modal-btn" onClick={onClose}>
            Close
          </button>
        </div>
      </div>
    </div>
  );
}

export default MeetingLinks;