import React, { useEffect, useRef } from 'react';
import VideoPlayer from './VideoPlayer';
import './VideoGrid.css';

function VideoGrid({ 
  localStream, 
  localUserName, 
  localRole, 
  localUserId,
  peers, 
  userVideoRef, 
  isAudioMuted, 
  isVideoOff,
  layout,
  fullscreenParticipant,
  onFullscreen,
  raisedHands
}) {
  const gridRef = useRef(null);

  // Calculate grid layout based on participant count
  const getGridLayout = () => {
    const totalParticipants = peers.length + 1; // +1 for local user
    
    if (fullscreenParticipant) {
      return 'fullscreen';
    }
    
    if (layout === 'speaker') {
      return 'speaker';
    }
    
    if (totalParticipants <= 2) {
      return 'single-row';
    } else if (totalParticipants <= 4) {
      return 'two-by-two';
    } else if (totalParticipants <= 6) {
      return 'three-by-two';
    } else if (totalParticipants <= 9) {
      return 'three-by-three';
    } else {
      return 'grid';
    }
  };

  const gridLayout = getGridLayout();

  // Check if hand is raised for a participant
  const isHandRaised = (userId) => {
    return raisedHands?.some(h => h.userId === userId) || false;
  };

  return (
    <div className={`video-grid-container ${gridLayout}`} ref={gridRef}>
      {/* Fullscreen mode */}
      {fullscreenParticipant && (
        <div className="fullscreen-video">
          {fullscreenParticipant === 'local' ? (
            <div className="video-wrapper local-video">
              <video
                ref={userVideoRef}
                autoPlay
                muted
                playsInline
                className="video-element mirror"
              />
              <div className="video-overlay">
                <div className="user-info">
                  <span className="user-name">{localUserName} (You)</span>
                  {localRole === 'host' && <span className="role-badge host">Host</span>}
                  {localRole === 'co-host' && <span className="role-badge cohost">Co-host</span>}
                  {isHandRaised(localUserId) && <span className="hand-icon">✋</span>}
                </div>
                <div className="video-controls-indicators">
                  {isAudioMuted && <i className="fas fa-microphone-slash muted-icon"></i>}
                  {isVideoOff && <i className="fas fa-video-slash video-off-icon"></i>}
                </div>
              </div>
              <button 
                className="fullscreen-exit"
                onClick={() => onFullscreen(null)}
              >
                <i className="fas fa-compress"></i>
              </button>
            </div>
          ) : (
            peers
              .filter(p => p.userId === fullscreenParticipant)
              .map(peer => (
                <VideoPlayer
                  key={peer.peerId}
                  peer={peer.peer}
                  userName={peer.userName}
                  userId={peer.userId}
                  role={peer.role}
                  isHandRaised={isHandRaised(peer.userId)}
                  isFullscreen={true}
                  onFullscreen={() => onFullscreen(null)}
                />
              ))
          )}
        </div>
      )}

      {/* Regular grid mode */}
      {!fullscreenParticipant && (
        <div className={`video-grid ${gridLayout}`}>
          {/* Local video */}
          <div className={`video-wrapper local-video ${isHandRaised(localUserId) ? 'hand-raised' : ''}`}>
            <video
              ref={userVideoRef}
              autoPlay
              muted
              playsInline
              className={`video-element mirror ${isVideoOff ? 'video-off' : ''}`}
            />
            <div className="video-overlay">
              <div className="user-info">
                <span className="user-name">{localUserName} (You)</span>
                {localRole === 'host' && <span className="role-badge host">Host</span>}
                {localRole === 'co-host' && <span className="role-badge cohost">Co-host</span>}
                {isHandRaised(localUserId) && <span className="hand-icon">✋</span>}
              </div>
              <div className="video-controls-indicators">
                {isAudioMuted && <i className="fas fa-microphone-slash muted-icon"></i>}
                {isVideoOff && <i className="fas fa-video-slash video-off-icon"></i>}
              </div>
            </div>
            <button 
              className="fullscreen-btn"
              onClick={() => onFullscreen('local')}
              title="Fullscreen"
            >
              <i className="fas fa-expand"></i>
            </button>
          </div>

          {/* Remote videos */}
          {peers.map((peer) => (
            <VideoPlayer
              key={peer.peerId}
              peer={peer.peer}
              userName={peer.userName}
              userId={peer.userId}
              role={peer.role}
              isHandRaised={isHandRaised(peer.userId)}
              onFullscreen={() => onFullscreen(peer.userId)}
            />
          ))}
        </div>
      )}

      {/* Empty state */}
      {peers.length === 0 && (
        <div className="empty-state">
          <div className="empty-state-content">
            <i className="fas fa-video"></i>
            <h3>Waiting for others to join</h3>
            <p>Share the meeting link with participants</p>
          </div>
        </div>
      )}
    </div>
  );
}

export default VideoGrid;