// Polyfills for simple-peer and WebRTC
import { Buffer } from 'buffer';
import process from 'process';  // This will now work after installing

// Polyfill process for browser
window.process = process;
window.Buffer = Buffer;

// Ensure global exists
if (typeof window.global === 'undefined') {
  window.global = window;
}

// Polyfill for setImmediate (used by simple-peer)
if (typeof window.setImmediate === 'undefined') {
  window.setImmediate = (cb) => setTimeout(cb, 0);
}