import React, { useState } from 'react';
import './HostControls.css';

function HostControls({ 
  meeting, 
  socket, 
  participants, 
  currentUser,
  onMuteAll, 
  onRemoveParticipant, 
  onMakeCoHost, 
  onRemoveCohost, 
  onEndMeeting, 
  onUpdateSettings,
  onLowerAllHands,
  onStartRecording,
  onStopRecording,
  onClose 
}) {
  const [activeTab, setActiveTab] = useState('participants');
  const [settings, setSettings] = useState(meeting?.settings || {});

  const handleSettingChange = (key, value) => {
    const newSettings = { ...settings, [key]: value };
    setSettings(newSettings);
    if (onUpdateSettings) {
      onUpdateSettings(newSettings);
    }
  };

  return (
    <div className="host-controls-modal">
      <div className="host-controls-content">
        <div className="host-controls-header">
          <h2>
            <i className="fas fa-crown"></i>
            Host Controls
          </h2>
          <button className="close-btn" onClick={onClose}>×</button>
        </div>

        <div className="host-controls-tabs">
          <button 
            className={`tab ${activeTab === 'participants' ? 'active' : ''}`}
            onClick={() => setActiveTab('participants')}
          >
            <i className="fas fa-users"></i>
            Participants
          </button>
          <button 
            className={`tab ${activeTab === 'settings' ? 'active' : ''}`}
            onClick={() => setActiveTab('settings')}
          >
            <i className="fas fa-cog"></i>
            Settings
          </button>
          <button 
            className={`tab ${activeTab === 'recording' ? 'active' : ''}`}
            onClick={() => setActiveTab('recording')}
          >
            <i className="fas fa-record-vinyl"></i>
            Recording
          </button>
        </div>

        <div className="host-controls-body">
          {activeTab === 'participants' && (
            <div className="participants-management">
              <button className="action-btn large" onClick={onMuteAll}>
                <i className="fas fa-microphone-slash"></i>
                Mute All
              </button>
              <button className="action-btn large" onClick={onLowerAllHands}>
                <i className="fas fa-hand-paper"></i>
                Lower All Hands
              </button>
              
              <div className="participants-list">
                <h3>Manage Participants</h3>
                {participants.map(p => (
                  <div key={p.userId} className="participant-row">
                    <span className="participant-name">
                      {p.name}
                      {p.role === 'host' && <span className="badge host">Host</span>}
                      {p.role === 'co-host' && <span className="badge cohost">Co-host</span>}
                    </span>
                    <div className="participant-row-actions">
                      {p.role !== 'host' && (
                        <>
                          {p.role === 'co-host' ? (
                            <button 
                              className="icon-btn"
                              onClick={() => onRemoveCohost(p.userId)}
                              title="Remove Co-host"
                            >
                              <i className="fas fa-star"></i>
                            </button>
                          ) : (
                            <button 
                              className="icon-btn"
                              onClick={() => onMakeCoHost(p.userId)}
                              title="Make Co-host"
                            >
                              <i className="fas fa-star"></i>
                            </button>
                          )}
                          <button 
                            className="icon-btn danger"
                            onClick={() => onRemoveParticipant(p.userId)}
                            title="Remove"
                          >
                            <i className="fas fa-times"></i>
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="settings-management">
              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.muteOnEntry || false}
                    onChange={(e) => handleSettingChange('muteOnEntry', e.target.checked)}
                  />
                  Mute participants on entry
                </label>
              </div>

              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.videoOffOnEntry || false}
                    onChange={(e) => handleSettingChange('videoOffOnEntry', e.target.checked)}
                  />
                  Video off on entry
                </label>
              </div>

              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.allowChat || true}
                    onChange={(e) => handleSettingChange('allowChat', e.target.checked)}
                  />
                  Allow chat
                </label>
              </div>

              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.allowScreenShare || true}
                    onChange={(e) => handleSettingChange('allowScreenShare', e.target.checked)}
                  />
                  Allow screen sharing
                </label>
              </div>

              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.allowUnmute || true}
                    onChange={(e) => handleSettingChange('allowUnmute', e.target.checked)}
                  />
                  Allow participants to unmute
                </label>
              </div>

              <div className="setting-item">
                <label>
                  <input
                    type="checkbox"
                    checked={settings.waitingRoom || false}
                    onChange={(e) => handleSettingChange('waitingRoom', e.target.checked)}
                  />
                  Enable waiting room
                </label>
              </div>

              <div className="setting-item">
                <label>Max Participants</label>
                <input
                  type="number"
                  value={settings.maxParticipants || 100}
                  onChange={(e) => handleSettingChange('maxParticipants', parseInt(e.target.value))}
                  min="1"
                  max="1000"
                />
              </div>
            </div>
          )}

          {activeTab === 'recording' && (
            <div className="recording-management">
              <div className="recording-actions">
                <button className="action-btn large primary" onClick={onStartRecording}>
                  <i className="fas fa-circle"></i>
                  Start Recording
                </button>
                <button className="action-btn large danger" onClick={onStopRecording}>
                  <i className="fas fa-square"></i>
                  Stop Recording
                </button>
              </div>
              <p className="recording-note">
                Recordings will be saved to the cloud and available after the meeting.
              </p>
            </div>
          )}
        </div>

        <div className="host-controls-footer">
          <button className="danger-btn end-meeting" onClick={onEndMeeting}>
            <i className="fas fa-phone-slash"></i>
            End Meeting for All
          </button>
        </div>
      </div>
    </div>
  );
}

export default HostControls;