import React from 'react';
import './Controls.css';

function Controls({ 
  isAudioMuted, 
  isVideoOff, 
  toggleAudio, 
  toggleVideo, 
  leaveRoom,
  role,
  onRaiseHand,
  isHandRaised,
  onLayoutChange,
  currentLayout
}) {
  return (
    <div className="controls-container">
      <div className="controls-left">
        <div className="meeting-time">
          <i className="far fa-clock"></i>
          <span>{new Date().toLocaleTimeString()}</span>
        </div>
      </div>

      <div className="controls-center">
        <button
          className={`control-btn audio ${isAudioMuted ? 'active' : ''}`}
          onClick={toggleAudio}
          title={isAudioMuted ? 'Unmute' : 'Mute'}
        >
          <i className={`fas fa-microphone${isAudioMuted ? '-slash' : ''}`}></i>
        </button>

        <button
          className={`control-btn video ${isVideoOff ? 'active' : ''}`}
          onClick={toggleVideo}
          title={isVideoOff ? 'Start Video' : 'Stop Video'}
        >
          <i className={`fas fa-video${isVideoOff ? '-slash' : ''}`}></i>
        </button>

        <button
          className={`control-btn hand ${isHandRaised ? 'active' : ''}`}
          onClick={onRaiseHand}
          title={isHandRaised ? 'Lower Hand' : 'Raise Hand'}
        >
          <i className="fas fa-hand-paper"></i>
        </button>

        <button
          className="control-btn leave"
          onClick={leaveRoom}
          title="Leave Meeting"
        >
          <i className="fas fa-phone-slash"></i>
        </button>
      </div>

      <div className="controls-right">
        {onLayoutChange && (
          <button
            className={`control-btn layout ${currentLayout === 'grid' ? 'active' : ''}`}
            onClick={() => onLayoutChange(currentLayout === 'grid' ? 'speaker' : 'grid')}
            title="Change Layout"
          >
            <i className={`fas fa-${currentLayout === 'grid' ? 'th-large' : 'user'}`}></i>
          </button>
        )}
        
        {role === 'host' && (
          <button
            className="control-btn host"
            title="Host Controls"
          >
            <i className="fas fa-crown"></i>
          </button>
        )}
      </div>
    </div>
  );
}

export default Controls;