import React from 'react';
import './ParticipantsPanel.css';

function ParticipantsPanel({ 
  participants, 
  currentUser, 
  localUser,
  raisedHands, 
  onMuteAll, 
  onMuteParticipant, 
  onRemoveParticipant, 
  onMakeCoHost, 
  onRemoveCohost, 
  onLowerAllHands,
  userRole 
}) {
  
  const isHost = userRole === 'host';
  const isCoHost = userRole === 'co-host';

  const handleMuteParticipant = (userId) => {
    if (onMuteParticipant) onMuteParticipant(userId);
  };

  const handleRemoveParticipant = (userId) => {
    if (onRemoveParticipant) onRemoveParticipant(userId);
  };

  const handleMakeCoHost = (userId) => {
    if (onMakeCoHost) onMakeCoHost(userId);
  };

  const handleRemoveCoHost = (userId) => {
    if (onRemoveCohost) onRemoveCohost(userId);
  };

  const getParticipantsList = () => {
    // Sort participants: hosts first, then co-hosts, then participants
    return [...participants].sort((a, b) => {
      if (a.role === 'host') return -1;
      if (b.role === 'host') return 1;
      if (a.role === 'co-host') return -1;
      if (b.role === 'co-host') return 1;
      return 0;
    });
  };

  return (
    <div className="participants-panel">
      <div className="participants-header">
        <h3>
          <i className="fas fa-users"></i>
          Participants ({participants.length + 1})
        </h3>
        {isHost && (
          <div className="host-actions">
            <button 
              className="action-btn" 
              onClick={onMuteAll}
              title="Mute All"
            >
              <i className="fas fa-microphone-slash"></i>
            </button>
            <button 
              className="action-btn" 
              onClick={onLowerAllHands}
              title="Lower All Hands"
            >
              <i className="fas fa-hand-paper"></i>
            </button>
          </div>
        )}
      </div>

      <div className="participants-list">
        {/* Local user (you) */}
        <div className="participant-item you">
          <div className="participant-info">
            <div className="participant-avatar">
              <i className="fas fa-user-circle"></i>
            </div>
            <div className="participant-details">
              <span className="participant-name">
                {localUser.name} (You)
                {localUser.role === 'host' && <span className="role-badge host">Host</span>}
                {localUser.role === 'co-host' && <span className="role-badge cohost">Co-host</span>}
              </span>
            </div>
          </div>
          <div className="participant-status">
            {raisedHands.some(h => h.userId === localUser.id) && (
              <span className="hand-icon" title="Hand raised">✋</span>
            )}
          </div>
        </div>

        {/* Other participants */}
        {getParticipantsList().map((participant) => (
          <div key={participant.userId} className="participant-item">
            <div className="participant-info">
              <div className="participant-avatar">
                <i className="fas fa-user-circle"></i>
              </div>
              <div className="participant-details">
                <span className="participant-name">
                  {participant.name}
                  {participant.role === 'host' && <span className="role-badge host">Host</span>}
                  {participant.role === 'co-host' && <span className="role-badge cohost">Co-host</span>}
                </span>
              </div>
            </div>
            <div className="participant-status">
              {!participant.audio && (
                <i className="fas fa-microphone-slash muted" title="Muted"></i>
              )}
              {!participant.video && (
                <i className="fas fa-video-slash video-off" title="Video off"></i>
              )}
              {raisedHands.some(h => h.userId === participant.userId) && (
                <span className="hand-icon" title="Hand raised">✋</span>
              )}
              
              {/* Host/Co-host controls */}
              {(isHost || (isCoHost && participant.role !== 'host')) && participant.userId !== localUser.id && (
                <div className="participant-controls">
                  {participant.role !== 'host' && (
                    <>
                      <button 
                        className="control-btn small"
                        onClick={() => handleMuteParticipant(participant.userId)}
                        title="Mute"
                      >
                        <i className="fas fa-microphone-slash"></i>
                      </button>
                      {isHost && (
                        <>
                          {participant.role === 'co-host' ? (
                            <button 
                              className="control-btn small"
                              onClick={() => handleRemoveCoHost(participant.userId)}
                              title="Remove Co-host"
                            >
                              <i className="fas fa-star"></i>
                            </button>
                          ) : (
                            <button 
                              className="control-btn small"
                              onClick={() => handleMakeCoHost(participant.userId)}
                              title="Make Co-host"
                            >
                              <i className="fas fa-star"></i>
                            </button>
                          )}
                          <button 
                            className="control-btn small danger"
                            onClick={() => handleRemoveParticipant(participant.userId)}
                            title="Remove"
                          >
                            <i className="fas fa-times"></i>
                          </button>
                        </>
                      )}
                    </>
                  )}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ParticipantsPanel;