import React, { useEffect, useRef } from 'react';

function VideoPlayer({ 
  peer, 
  userName, 
  userId, 
  role, 
  isHandRaised,
  onFullscreen,
  isFullscreen 
}) {
  const videoRef = useRef();

  useEffect(() => {
    if (!peer || peer.destroyed) return;

    console.log(`🎥 Setting up VideoPlayer for ${userName}`);

    const handleStream = (stream) => {
      console.log(`✅ Received stream for ${userName}:`, stream.getTracks().length, 'tracks');
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play()
          .then(() => console.log(`▶️ Video playing for ${userName}`))
          .catch(e => console.log('Play error:', e));
      }
    };

    const handleError = (err) => {
      console.error(`❌ VideoPlayer error for ${userName}:`, err);
    };

    const handleConnect = () => {
      console.log(`🔗 Peer connected for ${userName}`);
    };

    peer.on('stream', handleStream);
    peer.on('error', handleError);
    peer.on('connect', handleConnect);

    return () => {
      peer.off('stream', handleStream);
      peer.off('error', handleError);
      peer.off('connect', handleConnect);
      if (videoRef.current) {
        videoRef.current.srcObject = null;
      }
    };
  }, [peer, userName]);

  return (
    <div className={`video-wrapper ${isHandRaised ? 'hand-raised' : ''}`}>
      <video
        ref={videoRef}
        autoPlay
        playsInline
        className="video-element"
      />
      <div className="video-overlay">
        <div className="user-info">
          <span className="user-name">{userName}</span>
          {role === 'host' && <span className="role-badge host">Host</span>}
          {role === 'co-host' && <span className="role-badge cohost">Co-host</span>}
          {isHandRaised && <span className="hand-icon">✋</span>}
        </div>
      </div>
      {onFullscreen && (
        <button 
          className={`${isFullscreen ? 'fullscreen-exit' : 'fullscreen-btn'}`}
          onClick={() => onFullscreen(userId)}
          title={isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}
        >
          <i className={`fas fa-${isFullscreen ? 'compress' : 'expand'}`}></i>
        </button>
      )}
    </div>
  );
}

export default VideoPlayer;