import React, { useEffect, useRef, useState, useCallback } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import io from 'socket.io-client';
import Peer from 'simple-peer';
import VideoPlayer from './VideoPlayer';
import Controls from './Controls';
import './Room.css';

// Use relative URL - this will connect to the same host as your frontend
const socket = io({
  withCredentials: true,
  transports: ['websocket', 'polling'],
  reconnectionAttempts: 5,
  reconnectionDelay: 1000,
  timeout: 20000
});

function GuestRoom() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [isAudioMuted, setIsAudioMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [permissionDenied, setPermissionDenied] = useState(false);
  const [socketConnected, setSocketConnected] = useState(false);
  const [connectionAttempts, setConnectionAttempts] = useState(0);
  
  const userVideo = useRef();
  const peersRef = useRef(new Map());
  const socketRef = useRef(socket);
  const pendingSignals = useRef(new Map());
  
  // Get guest name and meeting info from URL params
  const queryParams = new URLSearchParams(location.search);
  const guestName = queryParams.get('name') || 'Guest';
  const meetingTitle = queryParams.get('title') || 'Meeting';
  const hostName = queryParams.get('host') || 'Host';

  // Generate a unique guest ID
  const guestId = useRef(`guest_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`);

  // Check connection status
  useEffect(() => {
    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected with ID:', socketRef.current.id);
      setSocketConnected(true);
      setError('');
      setConnectionAttempts(0);
    });

    socketRef.current.on('connect_error', (err) => {
      console.error('❌ Socket connection error:', err.message);
      setSocketConnected(false);
      setConnectionAttempts(prev => prev + 1);
      
      if (connectionAttempts >= 5) {
        setError('Cannot connect to server. Please check your internet connection and refresh.');
      }
    });

    socketRef.current.on('disconnect', (reason) => {
      console.log('🔴 Socket disconnected:', reason);
      setSocketConnected(false);
      
      if (reason === 'io server disconnect') {
        // Reconnect manually if server disconnected
        socketRef.current.connect();
      }
    });

    socketRef.current.on('reconnect', (attemptNumber) => {
      console.log('🔄 Socket reconnected after', attemptNumber, 'attempts');
      setSocketConnected(true);
      setError('');
    });

    socketRef.current.on('reconnect_error', (err) => {
      console.error('❌ Reconnection error:', err.message);
    });

    return () => {
      socketRef.current.off('connect');
      socketRef.current.off('connect_error');
      socketRef.current.off('disconnect');
      socketRef.current.off('reconnect');
      socketRef.current.off('reconnect_error');
    };
  }, [connectionAttempts]);

  const requestCameraPermission = async () => {
    try {
      console.log('Requesting camera access...');
      
      // Check if media devices are supported
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error('Your browser does not support camera access. Please use Chrome, Firefox, or Edge.');
      }

      // Try with basic constraints first
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: {
          width: { ideal: 1280 },
          height: { ideal: 720 },
          facingMode: 'user'
        }, 
        audio: true 
      });
      
      return stream;
    } catch (err) {
      console.error('Camera permission error:', err);
      
      // Try without audio if video works
      if (err.name === 'NotFoundError' || err.message.includes('audio')) {
        try {
          console.log('Trying video only...');
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: true, 
            audio: false 
          });
          return stream;
        } catch (videoErr) {
          // Re-throw with original error
        }
      }
      
      // Handle specific errors
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setPermissionDenied(true);
        throw new Error('Camera access denied. Please allow camera access in your browser settings and refresh.');
      } else if (err.name === 'NotFoundError') {
        throw new Error('No camera found on your device. You can still join without video.');
      } else if (err.name === 'NotReadableError') {
        throw new Error('Camera is already in use by another application. Please close other apps using your camera.');
      } else if (err.name === 'OverconstrainedError') {
        throw new Error('Camera cannot meet the requirements. Trying basic settings...');
      } else {
        throw new Error(`Camera error: ${err.message || 'Unknown error'}`);
      }
    }
  };

  // Create peer connection (initiator)
  const createPeer = useCallback((targetSocketId, stream) => {
    try {
      console.log('Creating peer for:', targetSocketId);
      
      const peer = new Peer({
        initiator: true,
        trickle: false,
        stream,
        config: {
          iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:stun1.l.google.com:19302' },
            { urls: 'stun:stun2.l.google.com:19302' },
            { urls: 'stun:stun3.l.google.com:19302' },
            { urls: 'stun:stun4.l.google.com:19302' }
          ]
        }
      });

      peer.on('signal', signal => {
        if (socketRef.current.connected) {
          socketRef.current.emit('offer', {
            targetSocketId,
            offer: signal
          });
        }
      });

      peer.on('stream', (remoteStream) => {
        console.log('✅ Received remote stream from:', targetSocketId);
      });

      peer.on('connect', () => {
        console.log('✅ Peer connected to:', targetSocketId);
      });

      peer.on('error', (err) => {
        console.error('❌ Peer error:', err);
      });

      peer.on('close', () => {
        console.log('🔴 Peer closed:', targetSocketId);
      });

      return peer;
    } catch (err) {
      console.error('Error creating peer:', err);
      return null;
    }
  }, []);

  // Add peer connection (for receiving)
  const addPeer = useCallback((targetSocketId, stream) => {
    try {
      console.log('Adding peer for:', targetSocketId);
      
      const peer = new Peer({
        initiator: false,
        trickle: false,
        stream,
        config: {
          iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:stun1.l.google.com:19302' },
            { urls: 'stun:stun2.l.google.com:19302' },
            { urls: 'stun:stun3.l.google.com:19302' },
            { urls: 'stun:stun4.l.google.com:19302' }
          ]
        }
      });

      peer.on('signal', signal => {
        if (socketRef.current.connected) {
          socketRef.current.emit('answer', {
            targetSocketId,
            answer: signal
          });
        }
      });

      peer.on('stream', (remoteStream) => {
        console.log('✅ Received remote stream from:', targetSocketId);
      });

      peer.on('connect', () => {
        console.log('✅ Peer connected to:', targetSocketId);
      });

      peer.on('error', (err) => {
        console.error('❌ Peer error:', err);
      });

      peer.on('close', () => {
        console.log('🔴 Peer closed:', targetSocketId);
      });

      return peer;
    } catch (err) {
      console.error('Error adding peer:', err);
      return null;
    }
  }, []);

  useEffect(() => {
    let isMounted = true;
    let stream = null;
    let mediaStream = null;

    const initializeMedia = async () => {
      try {
        // Check socket connection first
        if (!socketRef.current.connected) {
          console.log('Waiting for socket connection...');
          // Wait up to 10 seconds for socket connection
          await new Promise((resolve, reject) => {
            let attempts = 0;
            const maxAttempts = 50; // 5 seconds (50 * 100ms)
            
            const checkInterval = setInterval(() => {
              attempts++;
              if (socketRef.current.connected) {
                clearInterval(checkInterval);
                resolve();
              } else if (attempts >= maxAttempts) {
                clearInterval(checkInterval);
                reject(new Error('Socket connection timeout. Please refresh the page.'));
              }
            }, 100);
          });
        }

        // Request camera permission
        stream = await requestCameraPermission();
        mediaStream = stream;
        
        if (!isMounted) return;
        
        console.log('✅ Got local stream');
        setLocalStream(stream);
        setPermissionDenied(false);
        setError('');
        
        if (userVideo.current) {
          userVideo.current.srcObject = stream;
          try {
            await userVideo.current.play();
          } catch (playErr) {
            console.log('Play error (might be autoplay policy):', playErr);
          }
        }
        
        setLoading(false);

        // Join room
        socketRef.current.emit('join-room', {
          roomId,
          userId: guestId.current,
          userName: guestName,
          role: 'participant'
        });

        console.log('📤 Joined room:', roomId);

        // Socket event handlers
        socketRef.current.on('existing-users', (users) => {
          console.log('👥 Existing users:', users);
          
          const newPeers = [];
          users.forEach(user => {
            if (user.userId !== guestId.current && !peersRef.current.has(user.socketId)) {
              const peer = createPeer(user.socketId, stream);
              if (peer) {
                peersRef.current.set(user.socketId, {
                  peerId: user.socketId,
                  peer,
                  userName: user.userName
                });
                newPeers.push({
                  peerId: user.socketId,
                  peer,
                  userName: user.userName
                });
              }
            }
          });
          
          if (newPeers.length > 0) {
            setPeers(prev => [...prev, ...newPeers]);
          }
        });

        socketRef.current.on('user-connected', (newUser) => {
          console.log('🟢 User connected:', newUser);
          
          if (newUser.userId !== guestId.current && !peersRef.current.has(newUser.socketId)) {
            const peer = addPeer(newUser.socketId, stream);
            if (peer) {
              const newPeer = {
                peerId: newUser.socketId,
                peer,
                userName: newUser.userName
              };
              peersRef.current.set(newUser.socketId, newPeer);
              setPeers(prev => [...prev, newPeer]);
            }
          }
        });

        socketRef.current.on('offer', ({ offer, fromSocketId }) => {
          console.log('📞 Received offer from:', fromSocketId);
          
          if (!peersRef.current.has(fromSocketId)) {
            const peer = addPeer(fromSocketId, stream);
            if (peer) {
              const newPeer = {
                peerId: fromSocketId,
                peer,
                userName: 'Participant'
              };
              peersRef.current.set(fromSocketId, newPeer);
              setPeers(prev => [...prev, newPeer]);
              
              // Signal after a short delay to ensure peer is ready
              setTimeout(() => {
                const peerData = peersRef.current.get(fromSocketId);
                if (peerData && peerData.peer && !peerData.peer.destroyed) {
                  peerData.peer.signal(offer);
                }
              }, 500);
            }
          }
        });

        socketRef.current.on('answer', ({ answer, fromSocketId }) => {
          console.log('📞 Received answer from:', fromSocketId);
          
          const peerData = peersRef.current.get(fromSocketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            setTimeout(() => {
              if (peerData.peer && !peerData.peer.destroyed) {
                peerData.peer.signal(answer);
              }
            }, 100);
          } else {
            // Store for later
            if (!pendingSignals.current.has(fromSocketId)) {
              pendingSignals.current.set(fromSocketId, []);
            }
            pendingSignals.current.get(fromSocketId).push(answer);
          }
        });

        socketRef.current.on('ice-candidate', ({ candidate, fromSocketId }) => {
          const peerData = peersRef.current.get(fromSocketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            peerData.peer.signal(candidate);
          } else {
            // Store for later
            if (!pendingSignals.current.has(fromSocketId)) {
              pendingSignals.current.set(fromSocketId, []);
            }
            pendingSignals.current.get(fromSocketId).push(candidate);
          }
        });

        socketRef.current.on('user-disconnected', (socketId) => {
          console.log('🔴 User disconnected:', socketId);
          
          const peerData = peersRef.current.get(socketId);
          if (peerData && peerData.peer && !peerData.peer.destroyed) {
            peerData.peer.destroy();
          }
          
          peersRef.current.delete(socketId);
          pendingSignals.current.delete(socketId);
          setPeers(prev => prev.filter(p => p.peerId !== socketId));
        });

        socketRef.current.on('participant-muted', ({ userId }) => {
          if (userId === guestId.current) {
            setIsAudioMuted(true);
            if (stream) {
              stream.getAudioTracks()[0].enabled = false;
            }
          }
        });

        socketRef.current.on('participant-unmuted', ({ userId }) => {
          if (userId === guestId.current) {
            setIsAudioMuted(false);
            if (stream) {
              stream.getAudioTracks()[0].enabled = true;
            }
          }
        });

        socketRef.current.on('participant-removed', ({ userId }) => {
          if (userId === guestId.current) {
            alert('You have been removed from the meeting');
            cleanup();
            navigate('/');
          }
        });

        socketRef.current.on('meeting-ended', () => {
          alert('The meeting has ended');
          cleanup();
          navigate('/');
        });

      } catch (err) {
        console.error('❌ Error:', err);
        if (isMounted) {
          setError(err.message);
          setLoading(false);
        }
      }
    };

    initializeMedia();

    return () => {
      isMounted = false;
      cleanup();
      if (mediaStream) {
        mediaStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [roomId, guestName, createPeer, addPeer, navigate]);

  const cleanup = () => {
    // Remove all socket listeners
    socketRef.current.off('existing-users');
    socketRef.current.off('user-connected');
    socketRef.current.off('offer');
    socketRef.current.off('answer');
    socketRef.current.off('ice-candidate');
    socketRef.current.off('user-disconnected');
    socketRef.current.off('participant-muted');
    socketRef.current.off('participant-unmuted');
    socketRef.current.off('participant-removed');
    socketRef.current.off('meeting-ended');
    
    // Destroy all peers
    peersRef.current.forEach(({ peer }) => {
      if (peer && !peer.destroyed) {
        peer.destroy();
      }
    });
    peersRef.current.clear();
    pendingSignals.current.clear();
  };

  const toggleAudio = () => {
    if (localStream) {
      const audioTrack = localStream.getAudioTracks()[0];
      if (audioTrack) {
        const newMutedState = !audioTrack.enabled;
        audioTrack.enabled = !newMutedState;
        setIsAudioMuted(newMutedState);
        socketRef.current.emit('toggle-audio', { roomId, isMuted: newMutedState });
      }
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      const videoTrack = localStream.getVideoTracks()[0];
      if (videoTrack) {
        const newVideoState = !videoTrack.enabled;
        videoTrack.enabled = !newVideoState;
        setIsVideoOff(newVideoState);
        socketRef.current.emit('toggle-video', { roomId, isVideoOff: newVideoState });
      }
    }
  };

  const retryConnection = () => {
    window.location.reload();
  };

  const joinWithoutCamera = () => {
    setLoading(false);
    setError('');
    socketRef.current.emit('join-room', {
      roomId,
      userId: guestId.current,
      userName: guestName,
      role: 'participant'
    });
  };

  const leaveRoom = () => {
    cleanup();
    navigate('/');
  };

  const goToHome = () => {
    navigate('/');
  };

  if (!socketConnected && !error && connectionAttempts < 5) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Connecting to server...</p>
        <p className="permission-hint">Attempt {connectionAttempts + 1} of 5</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Requesting camera access...</p>
        <p className="permission-hint">Please allow camera and microphone access when prompted</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <div className="error-card">
          <i className="fas fa-exclamation-circle"></i>
          <h2>Connection Error</h2>
          <pre className="error-message-text">{error}</pre>
          
          <div className="error-actions">
            <button onClick={retryConnection} className="retry-btn">
              <i className="fas fa-redo"></i> Retry Connection
            </button>
            {permissionDenied && (
              <button onClick={joinWithoutCamera} className="join-without-btn">
                <i className="fas fa-volume-up"></i> Audio Only
              </button>
            )}
            <button onClick={goToHome} className="home-btn">
              <i className="fas fa-home"></i> Home
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="room-container">
      <div className="meeting-info-bar">
        <div className="meeting-details">
          <span className="meeting-title">{meetingTitle}</span>
          <span className="host-name">Host: {hostName}</span>
        </div>
        <div className="room-id-display">
          Room ID: <strong>{roomId}</strong>
        </div>
        {!socketConnected && (
          <div className="connection-status-warning">
            <i className="fas fa-exclamation-triangle"></i>
            Reconnecting...
          </div>
        )}
      </div>

      <div className="video-grid">
        {/* Local video */}
        <div className="video-wrapper">
          {localStream ? (
            <video
              ref={userVideo}
              autoPlay
              muted
              playsInline
              className="video-element"
            />
          ) : (
            <div className="no-video-placeholder">
              <i className="fas fa-video-slash"></i>
              <p>Camera not available</p>
            </div>
          )}
          <div className="user-name">
            {guestName} (You)
            <span className="guest-badge">Guest</span>
          </div>
          {isAudioMuted && <div className="muted-indicator">Muted</div>}
          {isVideoOff && <div className="video-off-indicator">Video Off</div>}
        </div>

        {/* Remote videos */}
        {peers.map((peer) => (
          <VideoPlayer
            key={peer.peerId}
            peer={peer.peer}
            userName={peer.userName}
          />
        ))}

        {/* Empty state */}
        {peers.length === 0 && !loading && (
          <div className="empty-state">
            <p>Waiting for others to join...</p>
            <p className="connection-status">Share the meeting link with others</p>
          </div>
        )}
      </div>

      <Controls
        isAudioMuted={isAudioMuted}
        isVideoOff={isVideoOff}
        toggleAudio={toggleAudio}
        toggleVideo={toggleVideo}
        leaveRoom={leaveRoom}
        role="participant"
      />
    </div>
  );
}

export default GuestRoom;